class Solution:
    def solve(self, graph: dict) -> int:
        count = 0
        visited = set()

        for node in graph:
            if node not in visited:
                self.dfs(graph, node, visited)
                count += 1

        return count

    def dfs(self, graph: dict, node: int, visited: set) -> None:
        visited.add(node)
        for neighbor in graph[node]:
            if neighbor not in visited:
                self.dfs(graph, neighbor, visited)

