class Solution {
public:
    int solve(std::map<int, std::vector<int>> graph) {
        int count = 0;
        std::unordered_set<int> visited;

        for (auto& it : graph) {
            if (visited.find(it.first) == visited.end()) {
                dfs(graph, it.first, visited);
                count++;
            }
        }
        return count;
    }

    void dfs(std::map<int, std::vector<int>>& graph, int node, std::unordered_set<int>& visited) {
        visited.insert(node);
        for (int neighbor : graph[node]) {
            if (visited.find(neighbor) == visited.end()) {
                dfs(graph, neighbor, visited);
            }
        }
    }
};
